// Busca o domínio direto no node Wait
const targetDomain = $node["Wait"].json["target_domain"] || 'unknown-domain';

// Pega os dados DNS do HTTP Request
const dnsRaw = $input.first().json.data;

// Se não tiver dados DNS, erro
if (!dnsRaw) {
  return {
    json: {
      error: 'No DNS data found',
      filename: 'OSINT_ERROR.txt',
      content: 'Error: No DNS data received from previous node',
      format: 'text'
    }
  };
}

// Timestamp para o nome do arquivo
const now = new Date();
const timestamp = now.getFullYear().toString() +
  String(now.getMonth() + 1).padStart(2, '0') +
  String(now.getDate()).padStart(2, '0') + '_' +
  String(now.getHours()).padStart(2, '0') +
  String(now.getMinutes()).padStart(2, '0') +
  String(now.getSeconds()).padStart(2, '0');

// Processa os dados DNS
const dnsLines = dnsRaw.split('\n').filter(line => line.trim() !== '');

const dnsRecords = {
  A: [],
  AAAA: [],
  MX: [],
  NS: [],
  TXT: [],
  SOA: []
};

dnsLines.forEach(line => {
  if (line.includes(' : ')) {
    const [type, value] = line.split(' : ', 2);
    const cleanType = type.trim();
    if (dnsRecords.hasOwnProperty(cleanType)) {
      dnsRecords[cleanType].push(value.trim());
    }
  }
});

// Relatório formatado (Markdown)
const report = `# 🔍 OSINT Infrastructure Analysis

## Target Domain
${targetDomain}

## Analysis Type
DNS Lookup

## DNS Infrastructure

### A Records (IPv4)
${dnsRecords.A.length > 0 ? dnsRecords.A.join('\n') : 'Nenhum registro encontrado'}

### AAAA Records (IPv6)
${dnsRecords.AAAA.length > 0 ? dnsRecords.AAAA.join('\n') : 'Nenhum registro encontrado'}

### MX Records (Mail)
${dnsRecords.MX.length > 0 ? dnsRecords.MX.join('\n') : 'Nenhum registro encontrado'}

### NS Records (Nameservers)
${dnsRecords.NS.length > 0 ? dnsRecords.NS.join('\n') : 'Nenhum registro encontrado'}

### TXT Records
${dnsRecords.TXT.length > 0 ? dnsRecords.TXT.map(txt => `- ${txt}`).join('\n') : 'Nenhum registro encontrado'}

---
Relatório gerado automaticamente via n8n OSINT Workflow
`;

// Retorna 3 itens (um para cada formato)
return [
  {
    json: {
      filename: `OSINT_${targetDomain}_${timestamp}.md`,
      content: report,
      format: 'markdown'
    }
  },
  {
    json: {
      filename: `OSINT_${targetDomain}_${timestamp}.json`,
      content: JSON.stringify({
        target_domain: targetDomain,
        analysis_type: 'DNS Lookup',
        dns_data: dnsRecords,
        generated_at: now.toISOString()
      }, null, 2),
      format: 'json'
    }
  },
  {
    json: {
      filename: `OSINT_${targetDomain}_${timestamp}.txt`,
      content: `OSINT DNS Report\n================\n\nDomain: ${targetDomain}\nDate: ${now.toLocaleString()}\n\n${Object.entries(dnsRecords).map(([type, values]) => 
        values.length > 0 ? `[${type}]\n${values.join('\n')}` : ''
      ).filter(Boolean).join('\n\n')}`,
      format: 'text'
    }
  }
];
